define(["jquery"], function($) {
    "use strict";
    var emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    function showResult(divId, success, message) {
        var cls = success ? "alert-success" : "alert-danger";
        var msg = message || 'Unexpected response from server';
        $("#" + divId).html('<div class="alert ' + cls + '">' + msg + "</div>");
    }
    return {
        init: function() {
            var ajaxUrl = M.cfg.wwwroot + "/local/msgraph_api_mailer/ajax.php";
            var sesskey = M.cfg.sesskey;
            $("#check-permissions-btn").on("click", function() {
                $("#permission-result").html('<div class="alert alert-info"><i class="fa fa-spinner fa-spin"></i> Checking permissions...</div>');
                $.ajax({
                    url: ajaxUrl, type: "POST", dataType: "json",
                    data: {action: "check_permissions", sesskey: sesskey},
                    success: function(r) { showResult("permission-result", r.success, r.message); },
                    error: function(xhr) { showResult("permission-result", false, "Error connecting to server (HTTP " + xhr.status + ")"); }
                });
            });
            $("#send-test-btn").on("click", function() {
                var email = $("#test-email-input").val().trim();
                if (!email) {
                    $("#email-result").html('<div class="alert alert-warning">Please enter an email address.</div>');
                    return;
                }
                if (!emailRe.test(email)) {
                    $("#email-result").html('<div class="alert alert-warning">Please enter a valid email address.</div>');
                    return;
                }
                $("#email-result").html('<div class="alert alert-info"><i class="fa fa-spinner fa-spin"></i> Sending test email...</div>');
                $.ajax({
                    url: ajaxUrl, type: "POST", dataType: "json",
                    data: {action: "send_test_email", email: email, sesskey: sesskey},
                    success: function(r) { showResult("email-result", r.success, r.message); },
                    error: function(xhr) { showResult("email-result", false, "Error connecting to server (HTTP " + xhr.status + ")"); }
                });
            });
            $("#test-email-input").on("keypress", function(e) {
                if (e.which === 13) { $("#send-test-btn").trigger("click"); }
            });
        }
    };
});